Here's a complete test class following MSTest 3.x+ best practices:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays until cancellation fires
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct);   // blocks until cancelled
            return new HttpResponseMessage();          // never reached
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately after starting
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledCooperatively()
    {
        // Arrange — handler that waits longer than the timeout
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);
            return new HttpResponseMessage();
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Assert — the token fires and the call is cancelled
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight test double — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken,
            Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage canned)
            : this((_, _) => Task.FromResult(canned)) { }

        public FakeHandler(
            Func<HttpRequestMessage, CancellationToken,
                Task<HttpResponseMessage>> send) => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance + design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `Assert.ThrowsExactlyAsync<T>` | Precise exception type check (not `[ExpectedException]`) |
| `FakeHandler` | No mocking library needed — `HttpMessageHandler` is the standard seam for `HttpClient` |
| Separate `CancellationTokenSource` for cancellation tests | Keeps cancellation tests independent from `[Timeout]` cancellation |

The third and fourth tests verify that your `FetchAsync` properly **propagates** the `CancellationToken` into `HttpClient.GetAsync` — if it didn't, those tests would hang until the `[Timeout]` fires.
